VALUES
  ('aboriginal-0a2fc18c-moex-00023', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-114-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '根據111年臺灣人力資源調查統計，臺灣地區總人口數約為2,309萬人，其中15歲以上民間人口 約為2,003萬人，包括勞動人口為1,185萬人，以及非勞動人口818萬人，其中想工作而未找工 作者且隨時可以開始工作者15萬人、料理家務者255萬人，以及高齡、身心障礙者282萬人等。 就業人口約為1,142萬人，則111年臺灣的失業率約為何？', '["2.1%", "3.6%", "3.9%", "5.2%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "9aa9fc32b976", "answer_pdf_sha1": "b963ad1973f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "509", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00024', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-114-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '根據貨幣數量學說（quantitytheoryofmoney）的關係，當名目貨幣數量的成長率為10%，貨幣流 通速度的成長率為2%，則名目國內生產毛額的成長率為何？', '["2%", "8%", "10%", "12%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "9aa9fc32b976", "answer_pdf_sha1": "b963ad1973f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "509", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00025', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-114-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '根據Solow成長模型，假設總合生產函數為Y=AK0.3L0.7，其中Y為總產出，A為當期的技術水 準，K為資本存量，L為勞動量。假設在長期均衡狀態，產出與資本的成長率為3%，勞動成長率 為1%，資本所得占總產出的比例為0.3，則技術進步成長率為何？', '["1.4%", "2.4%", "3.4%", "4%"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "9aa9fc32b976", "answer_pdf_sha1": "b963ad1973f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "509", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00026', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-114-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '若儲蓄率上升，將造成下列何種影響？', '["梭羅模型（Solowmodel）與AK模型的短期經濟成長率都上升", "梭羅模型與AK模型的長期經濟成長率都上升", "梭羅模型與AK模型的短期經濟成長率都下降", "梭羅模型與AK模型的長期經濟成長率都下降"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "9aa9fc32b976", "answer_pdf_sha1": "b963ad1973f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "509", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00027', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-114-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '有關經濟波動的敘述，下列何者正確？', '["對貨幣供給變動的外生干擾屬於名目變數衝擊，故它不是總合需求面衝擊", "古典學派經濟學家（classicaleconomists）認為，發生在生產力或勞動供給的外生干擾（shocks）， 以及貨幣面干擾，都是造成產出波動的主要原因", "經濟波動的起伏幅度並非規則變化，且波動的轉折時點亦非規律出現", "凱因斯學派經濟學家（Keynesianeconomists）認為財政政策變動是一種總合供給衝擊，可利用 做為反景氣循環（counter-cyclical）的一種政策工具"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "9aa9fc32b976", "answer_pdf_sha1": "b963ad1973f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "509", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00028', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-114-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '支付方式因為技術進步，變得多元化且快速。當經濟體的財富累積，而支付系統更有效率時，則 對貨幣需求的影響為何？', '["貨幣需求增加", "貨幣需求減少", "貨幣需求不變", "對貨幣需求的影響不明確"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "9aa9fc32b976", "answer_pdf_sha1": "b963ad1973f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "509", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00029', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-114-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '在宣布緊縮政府支出但不改變賦稅之條件下，下列何種情況會發生？', '["總合需求線不變，價格下降", "總合需求線不變，價格上升", "總合需求線向右移動", "總合需求線向左移動"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "9aa9fc32b976", "answer_pdf_sha1": "b963ad1973f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "509", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00030', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-114-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '假設一國經濟原先處在長期均衡狀態下，根據IS-LM與AD-AS模型，如果中央銀行對銀行存在 中央銀行的準備金收取利息，則在其他條件不變下，下列敘述何者正確？', '["長期均衡下，物價水準與名目利率都會上升", "長期均衡下，物價水準與名目利率都會下降", "長期均衡下，物價水準會上升且名目利率不變", "長期均衡下，實質GDP與名目利率都會上升"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "9aa9fc32b976", "answer_pdf_sha1": "b963ad1973f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "509", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00031', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-114-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '根據「李嘉圖均等」理論，「當政府降低本期的 ，並以所發行的公債挹注政府收入，由於 民眾預期未來會被加稅以償還公債，因此政府的政策對經濟體系沒有任何影響」，引號中的空格 為何？', '["所得稅", "定額稅", "從量稅", "從價稅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "9aa9fc32b976", "answer_pdf_sha1": "b963ad1973f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "509", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00032', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-114-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '下列何種理論與股票市場及廠商增加新投資與否有密切關係？', '["凱因斯理論", "Tobin’sq理論", "加速理論", "費雪理論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "9aa9fc32b976", "answer_pdf_sha1": "b963ad1973f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "509", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL)
